1	// ABOUTME: Chat panel UI module — rich markdown rendering of ACP agent conversations.
2	// ABOUTME: Manages chat tabs, WebSocket connections, streaming text, and tool call cards.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- Markdown setup ---
8	  marked.setOptions({
9	    highlight: function (code, lang) {
10	      if (lang && hljs.getLanguage(lang)) {
11	        return hljs.highlight(code, { language: lang }).value;
12	      }
13	      return hljs.highlightAuto(code).value;
14	    },
15	    breaks: true,
16	    gfm: true,
17	  });
18	
19	  // --- State ---
20	  var chatTabs = {};
21	  var activeChatTabId = null;
22	  var chatTabIdCounter = 0;
23	
24	  // --- DOM refs ---
25	  var $chatPanel = document.getElementById("chat-panel");
26	  var $chatTabs = document.getElementById("chat-tabs");
27	  var $chatMessages = document.getElementById("chat-messages");
28	  var $chatInput = document.getElementById("chat-input");
29	  var $chatSend = document.getElementById("chat-send");
30	  var $chatClose = document.getElementById("chat-close");
31	  var $chatCost = document.getElementById("chat-cost");
32	
33	
34	  // --- Helpers ---
35	
36	  function escapeHtml(s) {
37	    var div = document.createElement("div");
38	    div.textContent = s;
39	    return div.innerHTML;
40	  }
41	
42	  function renderMarkdown(text) {
43	    return DOMPurify.sanitize(marked.parse(text || ""));
44	  }
45	
46	  function generateChatTabId() {
47	    return "chat-" + (chatTabIdCounter++);
48	  }
49	
50	  function scrollToBottom() {
51	    if (!$chatMessages) return;
52	    $chatMessages.scrollTop = $chatMessages.scrollHeight;
53	  }
54	
55	  // --- Tool call icons by kind ---
56	  var TOOL_ICONS = {
57	    read: "&#128196;",     // page
58	    edit: "&#9998;",       // pencil
59	    execute: "&#9654;",    // play
60	    search: "&#128269;",   // magnifier
61	    "delete": "&#128465;", // trash
62	    think: "&#128161;",    // lightbulb
63	    fetch: "&#127760;",    // globe
64	  };
65	
66	  // --- Tab Management ---
67	
68	  function renderChatTabs() {
69	    $chatTabs.innerHTML = "";
70	    Object.keys(chatTabs).forEach(function (tabId) {
71	      var tab = chatTabs[tabId];
72	      var el = document.createElement("div");
73	      el.className = "chat-tab" + (tabId === activeChatTabId ? " active" : "");
74	      el.innerHTML =
75	        '<span class="chat-tab-title">' + escapeHtml(tab.title) + "</span>" +
76	        '<span class="chat-tab-close">&times;</span>';
77	
78	      el.querySelector(".chat-tab-title").addEventListener("click", function () {
79	        switchChatTab(tabId);
80	      });
81	      el.querySelector(".chat-tab-close").addEventListener("click", function (e) {
82	        e.stopPropagation();
83	        closeChatTab(tabId);
84	      });
85	      $chatTabs.appendChild(el);
86	    });
87	  }
88	
89	  function switchChatTab(tabId) {
90	    if (!chatTabs[tabId]) return;
91	    if (activeChatTabId && chatTabs[activeChatTabId]) {
92	      chatTabs[activeChatTabId].container.classList.remove("active");
93	    }
94	    activeChatTabId = tabId;
95	    chatTabs[tabId].container.classList.add("active");
96	    renderChatTabs();
97	    scrollToBottom();
98	    $chatInput.focus();
99	  }
100	
101	  function closeChatTab(tabId) {
102	    var tab = chatTabs[tabId];
103	    if (!tab) return;
104	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
105	      tab.ws.close();
106	    }
107	    if (tab.container && tab.container.parentNode) {
108	      tab.container.parentNode.removeChild(tab.container);
109	    }
110	    delete chatTabs[tabId];
111	
112	    var remaining = Object.keys(chatTabs);
113	    if (remaining.length > 0) {
114	      switchChatTab(remaining[remaining.length - 1]);
115	    } else {
116	      activeChatTabId = null;
117	      $chatPanel.classList.add("hidden");
118	      document.body.classList.remove("chat-open");
119	    }
120	    renderChatTabs();
121	  }
122	
123	  // --- Chat Tab Creation ---
124	
125	  function createChatTab(title, agent, cwd, existingSessionId, sessionSummary) {
126	    var tabId = generateChatTabId();
127	
128	    var container = document.createElement("div");
129	    container.className = "chat-tab-container";
130	    $chatMessages.appendChild(container);
131	
132	    var tabData = {
133	      id: tabId,
134	      ws: null,
135	      sessionId: null,
136	      agent: agent,
137	      cwd: cwd,
138	      container: container,
139	      title: title,
140	      streaming: false,
141	      currentTextAccum: "",
142	      currentTextEl: null,
143	      thinkingAccum: "",
144	      thinkingEl: null,
145	      renderScheduled: false,
146	      sessionSummary: sessionSummary || null,
147	    };
148	    chatTabs[tabId] = tabData;
149	
150	    // Show panel
151	    $chatPanel.classList.remove("hidden");
152	    document.body.classList.add("chat-open");
153	
154	    // Hide previous active tab
155	    if (activeChatTabId && chatTabs[activeChatTabId]) {
156	      chatTabs[activeChatTabId].container.classList.remove("active");
157	    }
158	    activeChatTabId = tabId;
159	    container.classList.add("active");
160	
161	    renderChatTabs();
162	    connectWebSocket(tabData, existingSessionId);
163	    $chatInput.focus();
164	
165	    return tabId;
166	  }
167	
168	  // --- WebSocket ---
169	
170	  function connectWebSocket(tabData, sessionId) {
171	    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
172	    var wsUrl = wsProtocol + "//" + location.host + "/ws/chat";
173	    var ws = new WebSocket(wsUrl);
174	    tabData.ws = ws;
175	
176	    ws.onopen = function () {
177	      ws.send(JSON.stringify({
178	        type: "start",
179	        agent: tabData.agent,
180	        cwd: tabData.cwd,
181	        sessionId: sessionId || undefined,
182	      }));
183	    };
184	
185	    ws.onmessage = function (evt) {
186	      try {
187	        var msg = JSON.parse(evt.data);
188	        handleServerMessage(tabData, msg);
189	      } catch (e) {
190	        console.error("Failed to parse chat message:", e);
191	      }
192	    };
193	
194	    ws.onclose = function () {
195	      tabData.streaming = false;
196	      updateInputState();
197	    };
198	
199	    ws.onerror = function () {
200	      appendSystemMessage(tabData, "Connection error");
201	    };
202	  }
203	
204	  // --- Message Routing ---
205	
206	  function handleServerMessage(tabData, msg) {
207	    switch (msg.type) {
208	      case "session_init":
209	        tabData.sessionId = msg.sessionId;
210	        if (msg.agentInfo) {
211	          appendSystemMessage(tabData, msg.agentInfo.title + " connected");
212	        }
213	        if (!msg.historyLoaded && tabData.sessionSummary) {
214	          appendInfoBanner(tabData, "Previous messages not available. " + tabData.sessionSummary);
215	        }
216	        break;
217	
218	      case "update":
219	        handleUpdate(tabData, msg);
220	        break;
221	
222	      case "turn_complete":
223	        finalizeAssistantMessage(tabData);
224	        tabData.streaming = false;
225	        updateInputState();
226	        break;
227	
228	      case "error":
229	        appendSystemMessage(tabData, "Error: " + (msg.message || "Unknown error"));
230	        tabData.streaming = false;
231	        updateInputState();
232	        break;
233	
234	      case "auth_required":
235	        appendAuthBanner(tabData, msg);
236	        break;
237	
238	      case "session_terminated":
239	        tabData.streaming = false;
240	        tabData.terminated = true;
241	        appendSessionTerminated(tabData);
242	        updateInputState();
243	        break;
244	
245	      case "session_restarted":
246	        tabData.terminated = false;
247	        tabData.sessionId = msg.sessionId || tabData.sessionId;
248	        appendSystemMessage(tabData, "Session resumed");
249	        break;
250	
251	      default:
252	        console.log("Unknown chat message type:", msg.type);
253	    }
254	  }
255	
256	  function handleUpdate(tabData, msg) {
257	    var su = msg.sessionUpdate;
258	    switch (su) {
259	      case "agent_message_chunk":
260	        var text = (msg.content && msg.content.text) || "";
261	        if (text) appendAgentText(tabData, text);
262	        break;
263	
264	      case "agent_thought_chunk":
265	        var thought = (msg.content && msg.content.text) || "";
266	        if (thought) appendThinking(tabData, thought);
267	        break;
268	
269	      case "user_message_chunk":
270	        var userText = (msg.content && msg.content.text) || "";
271	        if (userText) appendUserBubble(tabData, userText);
272	        break;
273	
274	      case "tool_call":
275	        renderToolCall(tabData, msg);
276	        break;
277	
278	      case "tool_call_update":
279	        updateToolCall(tabData, msg);
280	        break;
281	
282	      case "usage_update":
283	        renderUsage(msg);
284	        break;
285	
286	      case "plan":
287	        renderPlan(tabData, msg.entries || []);
288	        break;
289	
290	      default:
291	        // Gracefully ignore unknown update types
292	        break;
293	    }
294	  }
295	
296	  // --- Rendering: User Messages ---
297	
298	  function appendUserBubble(tabData, text) {
299	    // Close any open agent message
300	    finalizeAssistantMessage(tabData);
301	
302	    var bubble = document.createElement("div");
303	    bubble.className = "chat-bubble user";
304	    bubble.textContent = text;
305	    tabData.container.appendChild(bubble);
306	    scrollToBottom();
307	  }
308	
309	  // --- Rendering: Agent Text (streaming) ---
310	
311	  function appendAgentText(tabData, text) {
312	    // Close thinking if open
313	    finalizeThinking(tabData);
314	
315	    tabData.currentTextAccum += text;
316	    if (!tabData.currentTextEl) {
317	      var bubble = document.createElement("div");
318	      bubble.className = "chat-bubble assistant";
319	      var content = document.createElement("div");
320	      content.className = "chat-md-content";
321	      bubble.appendChild(content);
322	      tabData.container.appendChild(bubble);
323	      tabData.currentTextEl = content;
324	    }
325	    scheduleRender(tabData);
326	  }
327	
328	  function scheduleRender(tabData) {
329	    if (tabData.renderScheduled) return;
330	    tabData.renderScheduled = true;
331	    requestAnimationFrame(function () {
332	      tabData.renderScheduled = false;
333	      if (tabData.currentTextEl) {
334	        tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
335	      }
336	      scrollToBottom();
337	    });
338	  }
339	
340	  function finalizeAssistantMessage(tabData) {
341	    if (tabData.currentTextEl && tabData.currentTextAccum) {
342	      tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
343	    }
344	    tabData.currentTextEl = null;
345	    tabData.currentTextAccum = "";
346	    finalizeThinking(tabData);
347	  }
348	
349	  // --- Rendering: Thinking ---
350	
351	  function appendThinking(tabData, text) {
352	    tabData.thinkingAccum += text;
353	    if (!tabData.thinkingEl) {
354	      var block = document.createElement("details");
355	      block.className = "chat-thinking";
356	      block.innerHTML = "<summary>Thinking...</summary><div class='chat-thinking-content'></div>";
357	      tabData.container.appendChild(block);
358	      tabData.thinkingEl = block.querySelector(".chat-thinking-content");
359	    }
360	    tabData.thinkingEl.textContent = tabData.thinkingAccum;
361	    scrollToBottom();
362	  }
363	
364	  function finalizeThinking(tabData) {
365	    tabData.thinkingEl = null;
366	    tabData.thinkingAccum = "";
367	  }
368	
369	  // --- Rendering: Tool Calls ---
370	
371	  function renderToolCall(tabData, tc) {
372	    // Close thinking
373	    finalizeThinking(tabData);
374	
375	    var card = document.createElement("details");
376	    card.className = "chat-tool-card";
377	    card.setAttribute("data-tool-id", tc.toolCallId || "");
378	
379	    var status = tc.status || "pending";
380	    var kind = tc.kind || "other";
381	    var icon = TOOL_ICONS[kind] || "&#128295;"; // wrench default
382	    var title = tc.title || "Tool call";
383	    var locationText = "";
384	    if (tc.locations && tc.locations.length > 0) {
385	      var loc = tc.locations[0];
386	      var path = (loc && loc.path) || "";
387	      locationText = '<span class="chat-tool-path">' + escapeHtml(path.split("/").pop()) + "</span>";
388	    }
389	
390	    card.innerHTML =
391	      '<summary class="chat-tool-header">' +
392	        '<span class="chat-tool-icon">' + icon + "</span>" +
393	        '<span class="chat-tool-title">' + escapeHtml(title) + "</span>" +
394	        locationText +
395	        '<span class="chat-tool-status ' + escapeHtml(status) + '">' + escapeHtml(status) + "</span>" +
396	      "</summary>" +
397	      '<div class="chat-tool-body"></div>';
398	
399	    tabData.container.appendChild(card);
400	    scrollToBottom();
401	  }
402	
403	  function updateToolCall(tabData, update) {
404	    var card = tabData.container.querySelector(
405	      '.chat-tool-card[data-tool-id="' + (update.toolCallId || "") + '"]'
406	    );
407	    if (!card) return;
408	
409	    // Update status badge
410	    if (update.status) {
411	      var badge = card.querySelector(".chat-tool-status");
412	      if (badge) {
413	        badge.textContent = update.status;
414	        badge.className = "chat-tool-status " + update.status;
415	      }
416	    }
417	
418	    // Append content
419	    if (update.content && update.content.length > 0) {
420	      var body = card.querySelector(".chat-tool-body");
421	      if (body) {
422	        update.content.forEach(function (item) {
423	          if (item.type === "diff") {
424	            renderDiff(body, item);
425	          } else if (item.type === "content" && item.content) {
426	            var text = item.content.text || "";
427	            if (text) {
428	              var pre = document.createElement("pre");
429	              pre.className = "chat-tool-output";
430	              pre.textContent = text.length > 2000 ? text.substring(0, 2000) + "\n...(truncated)" : text;
431	              body.appendChild(pre);
432	            }
433	          }
434	        });
435	      }
436	    }
437	    scrollToBottom();
438	  }
439	
440	  function renderDiff(container, diff) {
441	    var el = document.createElement("div");
442	    el.className = "chat-diff";
443	    var header = document.createElement("div");
444	    header.className = "chat-diff-header";
445	    header.textContent = diff.path || "file";
446	    el.appendChild(header);
447	
448	    var pre = document.createElement("pre");
449	    pre.className = "chat-diff-content";
450	    // Simple diff display: show newText (the result)
451	    pre.textContent = diff.newText || "";
452	    el.appendChild(pre);
453	    container.appendChild(el);
454	  }
455	
456	  // --- Rendering: Plan ---
457	
458	  function renderPlan(tabData, entries) {
459	    // Remove any existing plan
460	    var existing = tabData.container.querySelector(".chat-plan");
461	    if (existing) existing.parentNode.removeChild(existing);
462	
463	    if (!entries.length) return;
464	
465	    var el = document.createElement("div");
466	    el.className = "chat-plan";
467	    el.innerHTML = "<div class='chat-plan-title'>Plan</div>";
468	    var list = document.createElement("ul");
469	    entries.forEach(function (entry) {
470	      var li = document.createElement("li");
471	      var statusIcon = entry.status === "completed" ? "&#10003;" : entry.status === "failed" ? "&#10007;" : "&#9744;";
472	      li.innerHTML = '<span class="chat-plan-icon">' + statusIcon + '</span> ' + escapeHtml(entry.content || "");
473	      li.className = "chat-plan-entry " + (entry.status || "pending");
474	      list.appendChild(li);
475	    });
476	    el.appendChild(list);
477	    tabData.container.appendChild(el);
478	    scrollToBottom();
479	  }
480	
481	  // --- Rendering: Usage ---
482	
483	  function renderUsage(msg) {
484	    if (!$chatCost) return;
485	    var cost = msg.cost;
486	    if (cost && cost.amount != null) {
487	      $chatCost.textContent = "$" + cost.amount.toFixed(4);
488	      $chatCost.classList.remove("hidden");
489	    }
490	  }
491	
492	  // --- Rendering: System / Info / Auth ---
493	
494	  function appendSystemMessage(tabData, text) {
495	    var el = document.createElement("div");
496	    el.className = "chat-system-msg";
497	    el.textContent = text;
498	    tabData.container.appendChild(el);
499	    scrollToBottom();
500	  }
501	
502	  function appendInfoBanner(tabData, text) {
503	    var el = document.createElement("div");
504	    el.className = "chat-info-banner";
505	    el.textContent = text;
506	    tabData.container.appendChild(el);
507	    scrollToBottom();
508	  }
509	
510	  function appendSessionTerminated(tabData) {
511	    var el = document.createElement("div");
512	    el.className = "chat-system-msg chat-terminated";
513	    el.textContent = "Session ended — send a message to resume";
514	    tabData.container.appendChild(el);
515	    scrollToBottom();
516	  }
517	
518	  function appendAuthBanner(tabData, msg) {
519	    var el = document.createElement("div");
520	    el.className = "chat-auth-banner";
521	    el.innerHTML =
522	      '<div class="chat-auth-text">' + escapeHtml(msg.message || "Authentication required") + "</div>" +
523	      '<button class="chat-auth-retry">Retry</button>';
524	    el.querySelector(".chat-auth-retry").addEventListener("click", function () {
525	      if (tabData.ws && tabData.ws.readyState === WebSocket.OPEN) {
526	        tabData.ws.send(JSON.stringify({ type: "retry" }));
527	        el.parentNode.removeChild(el);
528	      }
529	    });
530	    tabData.container.appendChild(el);
531	    scrollToBottom();
532	  }
533	
534	  // --- Input Handling ---
535	
536	  function sendUserMessage() {
537	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
538	    var tab = chatTabs[activeChatTabId];
539	    if (tab.streaming) return;
540	
541	    var text = $chatInput.value.trim();
542	    if (!text) return;
543	    $chatInput.value = "";
544	    $chatInput.style.height = "auto";
545	
546	    appendUserBubble(tab, text);
547	
548	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
549	      tab.ws.send(JSON.stringify({ type: "user_message", text: text }));
550	      tab.streaming = true;
551	      updateInputState();
552	    }
553	  }
554	
555	  function updateInputState() {
556	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
557	    var streaming = tab && tab.streaming;
558	    $chatInput.disabled = streaming;
559	    $chatSend.disabled = streaming;
560	    if (streaming) {
561	      $chatInput.placeholder = "Waiting for response...";
562	    } else if (tab && tab.terminated) {
563	      $chatInput.placeholder = "Send a message to resume session...";
564	    } else {
565	      $chatInput.placeholder = "Send a message...";
566	    }
567	  }
568	
569	  // Auto-grow textarea
570	  $chatInput.addEventListener("input", function () {
571	    this.style.height = "auto";
572	    this.style.height = Math.min(this.scrollHeight, 150) + "px";
573	  });
574	
575	  // Enter to send, Shift+Enter for newline
576	  $chatInput.addEventListener("keydown", function (e) {
577	    if (e.key === "Enter" && !e.shiftKey) {
578	      e.preventDefault();
579	      sendUserMessage();
580	    }
581	  });
582	
583	  $chatSend.addEventListener("click", sendUserMessage);
584	
585	  $chatClose.addEventListener("click", function () {
586	    // Close all tabs
587	    Object.keys(chatTabs).forEach(function (tabId) {
588	      var tab = chatTabs[tabId];
589	      if (tab.ws && tab.ws.readyState === WebSocket.OPEN) tab.ws.close();
590	      if (tab.container && tab.container.parentNode) tab.container.parentNode.removeChild(tab.container);
591	    });
592	    chatTabs = {};
593	    activeChatTabId = null;
594	    $chatPanel.classList.add("hidden");
595	    document.body.classList.remove("chat-open");
596	    renderChatTabs();
597	  });
598	
599	
600	  // --- Public API (called from app.js) ---
601	
602	  window.AgentChat = {
603	    openChat: function (session) {
604	      // Check for existing tab with same session
605	      var ids = Object.keys(chatTabs);
606	      for (var i = 0; i < ids.length; i++) {
607	        if (chatTabs[ids[i]].sessionId === session.id) {
608	          switchChatTab(ids[i]);
609	          return;
610	        }
611	      }
612	      var agent = session.source || "claude";
613	      var title = session.summary || session.id.substring(0, 8);
614	      createChatTab(title, agent, session.cwd, session.id, session.summary);
615	    },
616	
617	    openNewChat: function (cwd) {
618	      var agent = localStorage.getItem("ak-default-agent") || "claude";
619	      var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
620	      createChatTab("New: " + displayName, agent, cwd, null, null);
621	    },
622	  };
623	})();
624	
